+using namespace llvm;
+
+#define DEBUG_TYPE "constraint-elimination"
+
+namespace {
+
+using ConditionTy = std::tuple<CmpInst::Predicate, Value *, Value *>;
+using DecompEntry = std::pair<int64_t, Value *>;
+
+class Decomposition {
+  int64_t Offset = 0;
+  SmallVector<DecompEntry, 4> Vars;
+
+public:
+  Decomposition() = default;
+  Decomposition(Value *V) { Vars.push_back({1, V}); }
+  Decomposition(int64_t C, DecompEntry E) : Offset(C) { Vars.push_back(E); }
+
+  void add(const Decomposition &Other) {
+    Offset += Other.Offset;
+    Vars.append(Other.Vars.begin(), Other.Vars.end());
+  }
+
+  void mul(int64_t Scale) {
+    Offset *= Scale;
+    for (auto &P : Vars)
+      P.first *= Scale;
+  }
+};
+
+static bool hasNonNegativeRangeAttr(Value *V) {
+  auto *A = dyn_cast<Argument>(V);
+  if (!A || !A->hasAttribute(Attribute::Range))
+    return false;
+  return A->getRange().isAllNonNegative();
+}
+
+static bool isKnownNonNegativeFromContext(Value *V, const DataLayout &DL) {
+  return isKnownNonNegative(V, DL) || hasNonNegativeRangeAttr(V);
+}
+
+static Decomposition decompose(Value *V,
+                               SmallVectorImpl<ConditionTy> &Preconditions,
+                               bool IsSigned, const DataLayout &DL);
+
+static std::tuple<Value *, APInt, SmallVector<std::pair<Value *, APInt>, 4>,
+                  GEPNoWrapFlags>
+collectOffsets(GEPOperator &GEP, const DataLayout &DL) {
+  APInt ConstantOffset(DL.getIndexTypeSizeInBits(GEP.getType()), 0, true);
+  SmallVector<std::pair<Value *, APInt>, 4> VariableOffsets;
+
+  gep_type_iterator GTI = gep_type_begin(GEP);
+  for (User::op_iterator I = GEP.idx_begin(), E = GEP.idx_end(); I != E;
+       ++I, ++GTI) {
+    Value *Index = *I;
+    if (StructType *STy = GTI.getStructTypeOrNull()) {
+      ConstantOffset +=
+          APInt(ConstantOffset.getBitWidth(),
+                DL.getStructLayout(STy)->getElementOffset(GTI.getOperand()),
+                true);
+      continue;
+    }
+
+    APInt Scale(ConstantOffset.getBitWidth(),
+                GTI.getSequentialElementStride(DL), true);
+    if (auto *CI = dyn_cast<ConstantInt>(Index))
+      ConstantOffset += CI->getValue().sextOrTrunc(ConstantOffset.getBitWidth()) *
+                        Scale;
+    else
+      VariableOffsets.push_back({Index, Scale});
+  }
+
+  return {GEP.getPointerOperand(), ConstantOffset, VariableOffsets,
+          GEP.getNoWrapFlags()};
+}
+
 static Decomposition decomposeGEP(GEPOperator &GEP,
                                   SmallVectorImpl<ConditionTy> &Preconditions,
                                   bool IsSigned, const DataLayout &DL) {
@@ -464,7 +580,7 @@ static Decomposition decomposeGEP(GEPOperator &GEP,
     if (!NW.hasNoUnsignedWrap()) {
       // Try to prove nuw from nusw and nneg.
       assert(NW.hasNoUnsignedSignedWrap() && "Must have nusw flag");
-      if (!isKnownNonNegative(Index, DL))
+      if (!isKnownNonNegativeFromContext(Index, DL))
         Preconditions.emplace_back(CmpInst::ICMP_SGE, Index,
                                    ConstantInt::get(Index->getType(), 0));
     }
@@ -472,6 +588,51 @@ static Decomposition decomposeGEP(GEPOperator &GEP,
   return Result;
 }

+static Decomposition decompose(Value *V,
+                               SmallVectorImpl<ConditionTy> &Preconditions,
+                               bool IsSigned, const DataLayout &DL) {
+  if (auto *CI = dyn_cast<ConstantInt>(V))
+    return Decomposition(CI->getSExtValue(), DecompEntry(0, nullptr));
+
+  if (auto *GEP = dyn_cast<GEPOperator>(V))
+    return decomposeGEP(*GEP, Preconditions, IsSigned, DL);
+
+  return Decomposition(V);
+}
+
+struct ConstraintEliminationPass : public PassInfoMixin<ConstraintEliminationPass> {
+  PreservedAnalyses run(Function &F, FunctionAnalysisManager &AM) {
+    return PreservedAnalyses::all();
+  }
+};
+
+struct ConstraintElimination : public FunctionPass {
+  static char ID;
+  ConstraintElimination() : FunctionPass(ID) {
+    initializeConstraintEliminationPass(*PassRegistry::getPassRegistry());
+  }
+
+  bool runOnFunction(Function &F) override { return false; }
+
+  void getAnalysisUsage(AnalysisUsage &AU) const override {
+    AU.setPreservesCFG();
+  }
+};
+
+} // end anonymous namespace
+
+char ConstraintElimination::ID = 0;
+
+INITIALIZE_PASS_BEGIN(ConstraintElimination, DEBUG_TYPE, "Constraint Elimination",
+                      false, false)
+INITIALIZE_PASS_END(ConstraintElimination, DEBUG_TYPE, "Constraint Elimination",
+                    false, false)
+
+FunctionPass *llvm::createConstraintEliminationPass() {
+  return new ConstraintElimination();
+}
+
+
 // Decomposes \p V into a constant offset + list of pairs { Coefficient,
 // Variable } where Coefficient * Variable. The sum of the constant offset and
 // pairs equals \p V.
